#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X; scanf("%lld", &X);
        long long a = X;
        long long b = 3LL * X;
        printf("%lld %lld\n", a, b);
    }
    return 0;
}

